import{_ as a,o as i,c as r,ak as l}from"./chunks/framework.B5fSzMAO.js";const h=JSON.parse('{"title":"Requirements","description":"","frontmatter":{},"headers":[],"relativePath":"dotpi-box/requirements.md","filePath":"dotpi-box/requirements.md"}'),t={name:"dotpi-box/requirements.md"};function o(s,e,n,d,p,u){return i(),r("div",null,[...e[0]||(e[0]=[l('<h1 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to “Requirements”">​</a></h1><p>In this section we will go into detail about the required softwares, hardware and tools in order to build one speaker. Multiply each quantity by the number of speaker you want 😶.</p><p>You can download all the necessary files via <a href="../assets/dotpi-box/requirements/dotpi-box-files-V1.zip">this link</a></p><h2 id="softwares" tabindex="-1">Softwares <a class="header-anchor" href="#softwares" aria-label="Permalink to “Softwares”">​</a></h2><p>Here are a list of softwares you will need in order to carry out the project</p><ul><li>3D slicer (e.g. <a href="https://bambulab.com/fr-fr/download/studio" target="_blank" rel="noreferrer">Bambu Studio</a>, depending on the 3D printer you use)</li><li>Vector Graphics Editor (e.g. <a href="https://inkscape.fr/" target="_blank" rel="noreferrer">Inkscape</a>)</li><li>Optionally Fusion 360 if you want to edit the project (see <a href="./modify-the-project.html">Modify the project</a> if that is the case)</li></ul><h2 id="hardware" tabindex="-1">Hardware <a class="header-anchor" href="#hardware" aria-label="Permalink to “Hardware”">​</a></h2><p>You will need access to these machines in order to craft pieces :</p><ul><li>A 3D printer</li><li>A laser cutting machine</li></ul><p>You will also need this equipment (in most of the cases, aliases are ok, but make sure they fit into the project) :</p><ul><li>Raspberry Pi (3, 4 and 5 models fit)</li><li>Amp hat for Raspberry Pi (e.g. <a href="https://www.hifiberry.com/shop/boards/hifiberry-amp4/" target="_blank" rel="noreferrer">hifiberry Amp4</a>, <a href="https://www.kubii.com/fr/hat-dac-modules/3180-digiamp-iqaudio-5056561802398.html?srsltid=AfmBOopRUCgNysQ1d9cGiDGyEcOpquPpe75KvJQpEtNs2_MHh3MCSWyS" target="_blank" rel="noreferrer">IQAudio DAC DigiAMP+</a>)</li></ul><ul><li>USB-C trigger board</li><li>Speaker : <a href="https://www.visaton.de/en/products/drivers/fullrange-systems/sl-87-fe-8-ohm" target="_blank" rel="noreferrer">Visaton SL 87 FE</a></li><li>Electric cable : 50 centimeters</li><li>Screws : <ul><li>4 M4x5</li><li>4 M4x10</li><li>4 M2.5x6</li><li>4 M2.5x4 screws</li><li>4 M4x6 Heat Set Inserts</li><li>4 M4x4 Heat set Insterts</li><li>4 M2.5x8 spacers</li></ul></li><li>Optional external speaker connector</li><li>optional USB-C power bank (must be high voltage output compatible), a regular USB-C high voltage charger works as well</li></ul><h2 id="tools" tabindex="-1">Tools <a class="header-anchor" href="#tools" aria-label="Permalink to “Tools”">​</a></h2><ul><li>Soldering iron (and soldering tin)</li></ul><ul><li>Screwdrivers (Phillips and Allen)</li><li>Clamps : ideally a set of two frame clamps in addition to two regular clamps</li></ul><h2 id="consumables" tabindex="-1">Consumables <a class="header-anchor" href="#consumables" aria-label="Permalink to “Consumables”">​</a></h2><ul><li><p>5mm thick plywood : choose your favorite flavor 😶</p></li><li><p>Printable plastic :</p><ul><li><a href="https://eu.store.bambulab.com/fr/products/pla-basic-filament?srsltid=AfmBOooucgG2BoPO8a1Dwy1QoK1g2t13lUvoQLvoAfBuJwNmh87hIvBv" target="_blank" rel="noreferrer">PLA</a> : ~80 grams</li><li><a href="https://eu.store.bambulab.com/fr/products/paht-cf?srsltid=AfmBOoqrvgd3eTTRRenxCHPcnOVgsukZbFgH4hbD313MDA9TsjEdw_6B" target="_blank" rel="noreferrer">PAHT-CF</a> : ~50 grams</li></ul></li></ul><div class="info custom-block"><p class="custom-block-title custom-block-title-default">INFO</p><p>Indicated plastic quantities are approximate since they depend on how you print parts. We will go deeper into printing details later in this tutorial. In any case, make sure you have a bit more than you need</p></div><ul><li>Glue : <ul><li>Wood glue</li><li>Epoxy glue (or equivalent but shall be plastic and wood compatible)</li><li>Thread lock</li></ul></li><li>Soldering tin</li><li>Speaker fixation ring foam (other fixation technics to avoid solid vibrations are welcome)</li><li>Inside speaker foam</li></ul>',19)])])}const m=a(t,[["render",o]]);export{h as __pageData,m as default};
